  subject:   `Tu llegada a Porta D'irta — todo listo para ti`,
  body:      htmlBody,
  bookingId: b.bookingId,
}}];

// ── Compute Price Recommendations ──────────────────────────────────────────
// Reads Beds24 availability for 45 days, computes per-room yield prices,
// groups into ranges, compares with last applied prices.

const availData = items[0].json;
const rooms = availData.data || [];

const rules = {
  rooms: [
    {roomId: 662792, name: 'Torre Badum',        base: 90,  floor: 70,  ceiling: 180},
    {roomId: 662793, name: 'Cala El Pebret',     base: 100, floor: 80,  ceiling: 190},
    {roomId: 662794, name: 'Cala Aljub',         base: 100, floor: 80,  ceiling: 190},
    {roomId: 662795, name: 'Ermita Sant Antoni',  base: 120, floor: 95,  ceiling: 220},
  ],
  tiers: [
    {occupancyMin: 0,  occupancyMax: 50,  multiplier: 1.00},
    {occupancyMin: 51, occupancyMax: 70,  multiplier: 1.15},
    {occupancyMin: 71, occupancyMax: 85,  multiplier: 1.30},
    {occupancyMin: 86, occupancyMax: 100, multiplier: 1.50},
  ],
  specialDates: {
    '2026-04-02': 1.35, '2026-04-03': 1.35, '2026-04-05': 1.35, '2026-04-06': 1.30,
    '2026-06-24': 1.30, '2026-07-25': 1.30,
    '2026-08-14': 1.40, '2026-08-15': 1.50,
    '2026-12-06': 1.25, '2026-12-08': 1.25,
  }
};

// Collect all dates
const allDates = new Set();
for (const room of rooms) Object.keys(room.availability || {}).forEach(d => allDates.add(d));
const sortedDates = [...allDates].sort();
const numRooms = rooms.length || 4;

// Property-level occupancy per date
const dateOcc = {};
for (const date of sortedDates) {
  let booked = 0;
  for (const room of rooms) {
    if (room.availability?.[date] === false) booked++;
  }
  dateOcc[date] = Math.round((booked / numRooms) * 100);
}

// Static data tracks last applied prices: { room_662792: { '2026-04-01': 90, ... } }
const sd = $getWorkflowStaticData('global');
if (!sd.appliedPrices) sd.appliedPrices = {};

const allAdjustments = [];

for (const roomRule of rules.rooms) {
  const roomData = rooms.find(r => r.roomId === roomRule.roomId);
  if (!roomData) continue;

  // Group consecutive dates with same recommended price into ranges
  let curPrice = null, rangeStart = null, rangeEnd = null;
  const ranges = [];

  for (const date of sortedDates) {
    const occ = dateOcc[date] || 0;
    const tier = rules.tiers.find(t => occ >= t.occupancyMin && occ <= t.occupancyMax) || rules.tiers[0];
    const specMul = rules.specialDates[date] || 0;
    const mul = Math.max(tier.multiplier, specMul);
    const price = Math.max(roomRule.floor,
                    Math.min(roomRule.ceiling,
                      Math.round((roomRule.base * mul) / 5) * 5));

    if (price !== curPrice) {
      if (rangeStart) ranges.push({from: rangeStart, to: rangeEnd, price1: curPrice});
      curPrice = price;
      rangeStart = date;
    }
    rangeEnd = date;
  }
  if (rangeStart) ranges.push({from: rangeStart, to: rangeEnd, price1: curPrice});

  // Filter: only include ranges where price differs from last applied
  const roomKey = 'room_' + roomRule.roomId;
  const applied = sd.appliedPrices[roomKey] || {};

  for (const rng of ranges) {
    const prevPrice = applied[rng.from] ?? roomRule.base;
    if (Math.abs(rng.price1 - prevPrice) >= 5) {
      allAdjustments.push({
        roomId:   roomRule.roomId,
        roomName: roomRule.name,
        from:     rng.from,
        to:       rng.to,
        price1:   rng.price1,
        prevPrice,
        occ:      dateOcc[rng.from] || 0,
      });
    }
  }
}

allAdjustments.sort((a, b) => a.from.localeCompare(b.from));

return [{json: {
  adjustments: allAdjustments,
  hasAdjustments: allAdjustments.length > 0,
  numDates: sortedDates.length,
  dateOcc,
}}];

